    class Solution:
        def reverseVowels(self, s: str) -> str:
            vowels = {'a', 'e', 'i', 'o', 'u'}
            vowels_list = []
            for char in s:
                if char.lower() in vowels:
                    vowels_list.append(char)
            vowels_list.reverse()
            result = []
            ptr = 0
            for char in s:
                if char.lower() in vowels:
                    result.append(vowels_list[ptr])
                    ptr += 1
                else:
                    result.append(char)
            return ''.join(result)

